# rebuild spans_output
spans_output = []

for t in ayat_texts:
    start = text.find(t)
    end = start + len(t)
    spans_output.append({
        "span_start": start,
        "span_end": end,
        "span_text": t,
        "citation_type": "Aya"
    })

# add hadith occurrences
hadith_text = "إنما بعثت معلما"
idx = 0
while True:
    idx = text.find(hadith_text, idx)
    if idx == -1:
        break
    spans_output.append({
        "span_start": idx,
        "span_end": idx + len(hadith_text),
        "span_text": hadith_text,
        "citation_type": "Hadeeth"
    })
    idx += len(hadith_text)

# sort
spans_output_sorted = sorted(spans_output, key=lambda x: x["span_start"])
for s in spans_output_sorted:
    print(s)
